#!/bin/bash NETWORK="172.16.1.0/24" OUTPUT="scan" mkdir -p $OUTPUT echo "[+] Descobrindo hosts ativos..." nmap -sn $NETWORK -oG - | awk '/Up$/{print $2}' > $OUTPUT/hosts.txt echo "[+] Hosts encontrados:" cat $OUTPUT/hosts.txt echo for ip in $(cat $OUTPUT/hosts.txt); do echo "[+] Scan rápido em $ip" nmap -Pn -T4 --min-rate=1000 -p- $ip \ -oN $OUTPUT/${ip}_ports.txt PORTS=$(grep "^[0-9]" $OUTPUT/${ip}_ports.txt | \ cut -d "/" -f1 | tr '\n' ',' | sed 's/,$//') if [ ! -z "$PORTS" ]; then echo "[+] Enumerando serviços em $ip -> $PORTS" nmap -sV -sC -p$PORTS $ip \ -oN $OUTPUT/${ip}_services.txt fi done
